import math
from math import log, sqrt, exp, erf
def N(x): return 0.5*(1+erf(x/sqrt(2)))
def bs(S,K,T,r,sig,typ):
    d1=(log(S/K)+(r+0.5*sig*sig)*T)/(sig*sqrt(T))
    d2=d1-sig*sqrt(T)
    if typ=='c':
        price=S*N(d1)-K*exp(-r*T)*N(d2); delta=N(d1)
    else:
        price=K*exp(-r*T)*N(-d2)-S*N(-d1); delta=N(d1)-1
    return price,delta
S=100;r=0.04;sig=0.25;T=45/365
# scan strikes for ~0.30 / ~0.25 / 0.20 delta call and put
for K in [105,108,110,112,115]:
    p,d=bs(S,K,T,r,sig,'c'); print('CALL K',K,'delta %.2f'%d,'prem %.2f'%p)
print()
for K in [85,88,90,92,95]:
    p,d=bs(S,K,T,r,sig,'p'); print('PUT  K',K,'delta %.2f'%d,'prem %.2f'%p)
